using System.Threading.Channels;

/// <summary>
/// .NET 8 migration of BackgroundProcessor.
///
/// Key changes from .NET Framework:
///   1. Thread.Abort() / ThreadAbortException / Thread.ResetAbort() are all
///      removed — they throw PlatformNotSupportedException at runtime.
///   2. Replaced with CancellationToken for cooperative cancellation.
///   3. Raw Thread replaced with Task.Run (uses ThreadPool, avoids manual
///      lifecycle management).
///   4. Blocking GetNextItem() replaced with Channel<T> which supports
///      async + cancellation natively — the token unblocks the wait.
///   5. IAsyncDisposable for deterministic shutdown.
/// </summary>
public sealed class BackgroundProcessor : IAsyncDisposable
{
    private readonly Channel<WorkItem> _channel =
        Channel.CreateBounded<WorkItem>(capacity: 1024);

    private readonly CancellationTokenSource _cts = new();
    private Task? _workerTask;

    public void Start()
    {
        _workerTask = Task.Run(() => ProcessLoopAsync(_cts.Token));
    }

    /// <summary>
    /// Enqueue work (replaces whatever fed GetNextItem before).
    /// </summary>
    public ValueTask EnqueueAsync(WorkItem item, CancellationToken ct = default)
        => _channel.Writer.WriteAsync(item, ct);

    private async Task ProcessLoopAsync(CancellationToken ct)
    {
        // ChannelReader.ReadAllAsync yields items until the channel is
        // completed AND empty, or the token is cancelled.
        await foreach (var item in _channel.Reader.ReadAllAsync(ct))
        {
            try
            {
                await ProcessItemAsync(item, ct);
            }
            catch (OperationCanceledException) when (ct.IsCancellationRequested)
            {
                // Graceful shutdown requested — roll back in-flight work
                // exactly as the old ThreadAbortException handler did.
                RollbackCurrentTransaction();
                break;
            }
            finally
            {
                FlushBuffers();
            }
        }
    }

    public async ValueTask DisposeAsync()
    {
        // 1. Signal cancellation (replaces _running = false)
        await _cts.CancelAsync();

        // 2. Complete the channel so ReadAllAsync can finish
        _channel.Writer.TryComplete();

        // 3. Wait for the worker with a timeout (replaces Thread.Sleep + Abort)
        if (_workerTask is not null)
        {
            // Give the loop up to 2 seconds, then move on.
            // No Abort() equivalent needed — the token already
            // interrupted any blocking call.
            await _workerTask.WaitAsync(TimeSpan.FromSeconds(2))
                             .ConfigureAwait(ConfigureAwaitOptions.SuppressThrowing);
        }

        _cts.Dispose();
    }

    // --- stubs for illustration ---
    private Task ProcessItemAsync(WorkItem item, CancellationToken ct) => Task.CompletedTask;
    private void RollbackCurrentTransaction() { }
    private void FlushBuffers() { }
}

public record WorkItem(string Payload);

